import { ZnDataBulkEdit, ZnSavedFilterValue } from './mx-zing-grid.interface';

/** Returns an array of items that fit the search critera for MxFilterer. */
export function getMxFilteredData(znRefData: ZnDataBulkEdit[], propertySearchMapping: ZnSavedFilterValue) {
  return znRefData.filter((item) => {
    for (const property in propertySearchMapping) {
      const text: string = item[property];
      let foundMatch = false;
      for(const searchQuery of propertySearchMapping[property]) {
        if(text?.toLowerCase().includes(searchQuery.toLowerCase())) {
          foundMatch = true;
        }
      }
      if(!foundMatch) {
        return false;
      }
    }
    return true;
  });
}
