import 'regenerator-runtime/runtime';
import { Component, Element, Event, EventEmitter, h, Host, Method, Prop, State, Watch } from '@stencil/core';
import { isNullOrUndefined, isNullOrUndefinedOrEmptyString, uppercaseFirstLetter } from '@src/utils/mx-utils/utils';
import { getNewUuid } from '@src/utils/mx-utils/item-uuids';
import isEmpty from 'lodash.isempty';
import {
  ZNCellHeight,
  ZnData,
  ZnDataBulkEdit,
  ZnEnclosedEvent,
  ZnFilterInfo,
  ZnSavedFilterValue,
  ZnRegisterMethods
} from './mx-zing-grid.interface';
import { getMxFilteredData } from './mx-zing-grid.utils';

@Component({
  tag: 'mx-zing-grid',
  styleUrl: 'mx-zing-grid.css'
})
export class MxZingGrid {

  /** host element **/
  @Element() hostEl: HTMLMxZingGridElement;

  /** Sets the height of the grid cells. Defaults to medium(40px). */
  @Prop() readonly cellHeight: ZNCellHeight = ZNCellHeight.Medium;

  /**
   * @description Sets the data for the table.
   * @property id - This is required for all items in order for bulk edit functionality to work. */
  @Prop() readonly data: ZnData = [];
  @State() _data: ZnData = [];

  @Watch('cellHeight')
  onCellHeightChange(newValue: ZNCellHeight) {
    if (!isNullOrUndefined(this.znRef) && !isEmpty(this.znRef)) {
      this.updateCellHeight(newValue);
    }
  }

  /** excluded columns from the bulk edit. **/
  @Prop() readonly specialAdditions: string[] = [];
  @State() _specialAdditions: string[] = this.specialAdditions;

  // "populatedData" serves to keep track of the parent item (without actually going to the data).
  // This is used to determine what properties can be drilled through.
  @State() populatedData: Object | Object[] = this.data;

  /** Register custom methods on ZingGrid. **/
  @Prop() readonly registerMethods: ZnRegisterMethods[];

  /** Whether or not to use the MxContextMenu for features such as Drill Through. Defaults to true. **/
  @Prop() readonly useMxContextMenu: boolean = true;

  /** Method that will be called on bulk edit button click if present **/
  @Prop() readonly overrideBulkEditButtonHandler: () => void | null = null;

  @Watch('data')
  async watchData() {
    this.populatedData = this.data;
    this._data = Array.isArray(this.data) ? this.data : ('data' in this.data ? this.data.data : []);
    if (!isNullOrUndefined(this.znRef) && !isEmpty(this.znRef)) {
      this.znRef.executeOnLoad(async() => {
        this.znRef.setData(this._data, false);
        await this.initMxFilterer();
        // repaint based on the UI size
        this.znRef.updateSize(true, 0);
      });
    }
  }

  @Watch('specialAdditions')
  watchSpecialAdditions(specialAdditions: string[]) {
    this._specialAdditions = specialAdditions;
  }

  /** Emits an event with the data that was bulk edited. **/
  @Event() bulkRecordUpdate: EventEmitter<ZnDataBulkEdit[]>;

  private znRef: ZSoft.ZingGrid;

  private bulkEditModal: HTMLMxModalElement;
  private bulkEditModalContainer: HTMLElement;
  private bulkEditButton: HTMLElement;
  private drillResetButton: HTMLElement;
  private mxContextMenuContainer: HTMLDivElement;
  private mxContextMenuItemsContainer: HTMLDivElement;

  private previousPropertySearchMapping: ZnSavedFilterValue;

  private enclosedEvents: ZnEnclosedEvent[] = [
    {
      eventName: 'row:click',
      command: (evt: CustomEvent) => evt.detail.ZGTarget.classList.toggle('active')
    },
    {
      eventName: 'row:select',
      command: (evt: CustomEvent) => this.toggleBulkEdit(evt.detail.ZGData.selectedRows.length)
    },
    {
      // These have to be `any` because ZingGrid does not expose keyboard events for us.
      eventName: 'keydown' as any,
      command: (evt: any) => this.handleCellEdit(evt)
    }
  ];

  constructor() {
    // Registering custom renderers. Refer to the following:
    // registerMethod(): https://www.zinggrid.com/docs/api/methods/zinggrid-object#registermethod
    // Custom renderers: https://www.zinggrid.com/docs/features/custom-columns#renderer-function
    ZingGrid.registerMethod(this.dropdownRenderer('mx-single-select', 'itemChange'), 'mx-single-select');
    ZingGrid.registerMethod(this.dropdownRenderer('mx-multi-select', 'selectionChanged'), 'mx-multi-select');
    ZingGrid.registerMethod(this.accordionRenderer, 'mx-accordion-renderer');
    ZingGrid.registerMethod(this.tagRenderer, 'mx-tag-renderer');
    this.registerExternalMethods();
  }

  componentWillLoad() {
    ZingGrid.registerMethod(this.dropdownRenderer('mx-single-select', 'itemChange'), 'mx-single-select');
    ZingGrid.registerMethod(this.dropdownRenderer('mx-multi-select', 'selectionChanged'), 'mx-multi-select');
    ZingGrid.registerMethod(this.accordionRenderer, 'mx-accordion-renderer');
    ZingGrid.registerMethod(this.tagRenderer, 'mx-tag-renderer');
    this.registerExternalMethods();
    this._data = Array.isArray(this.data) ? this.data : ('data' in this.data ? this.data.data : []);
  }

  componentDidLoad() {
    this.znRef = this.hostEl.querySelector('zing-grid');
    if (!isNullOrUndefined(this.znRef) && !isEmpty(this.znRef)) {
      this.znRef.executeOnLoad(() => this.initZingGrid());
    }
  }

  private registerExternalMethods() {
    if (!isNullOrUndefined(this.registerMethods) && this.registerMethods.length > 0) {
      this.registerMethods.forEach((method) => {
        ZingGrid.registerMethod(method.fn, method.methodName);
      });
    }
  }

  private async initZingGrid() {
    this.znRef.setData(this._data, false);
    this.insertBulkEdit();
    this.updateCellHeight(this.cellHeight);
    this.addContextMenu();
    this.enclosedEvents.forEach((item) => this.znRef.addEventListener(item.eventName, item.command));
    await this.initMxFilterer();
  }

  private handleCellEdit(event: KeyboardEvent) {
    if (event.key === 'Escape' || ((event.key === 'z' || event.key === 'Z') && (event.ctrlKey || event.metaKey))) {
      event.preventDefault();
      event.stopPropagation();
      // The "widget" property and everything belonging to it is undocumented.
      this.znRef.widget.recordEditor.cancelOpenEdit();
      this.znRef.closeDialog();
    }
  }

  private updateCellHeight(height: ZNCellHeight) {
    // Let's force consumers to select one of our predefined heights to ensure consistency.
    if (!this.isValidCellHeight(height)) {
      throw new Error(`🚨Invalid height: ${height}. Please select a valid cell height for mx-zing-grid.`);
    } 
    this.znRef.executeOnLoad(() => {
      this.znRef.rowHeight = height;
      this.znRef.updateSize(true, 1);
    });
  }

  private readonly isValidCellHeight = (height: ZNCellHeight) => !isNullOrUndefined(ZNCellHeight[height])
                                                                 || height === "auto";

  private getValidFilterValues(filterValue: string) {
    return filterValue.split(',')
      .map((val) => val.trim())
      .filter((item) => item.length > 0);
  }

  /** Initializes the custom mxFilterer and replaces ZingGrid's internal filtering on all zg-filter input elements with it.
   * This should be called whenever the grid's data is changed externally(outside of ZingGrid manipulation).
   * As a rule of thumb: if you are updating ZingGrid data directly, via the <zing-grid> reference, instead of
   * utilizing our <mx-zing-grid>'s `data` prop, you should call this method.
   */
  @Method()
  async initMxFilterer() {
    // The "widget" property and everything belonging to it is undocumented.
    // We're overriding ZingGrid functions customOn() and fireFilterEvent() here in order to have direct
    // access to the filter. This *replaces* their filtering with our own.
    this.znRef.widget.aFilters.forEach((oDOMFilter: ZSoft.ZGFilter) => {
      oDOMFilter.customOn = () => {
        oDOMFilter.fireFilterEvent();
      };
      oDOMFilter.fireFilterEvent = () => {
        const savedFilterValues = this.getZgFilterValues(oDOMFilter);
        const filterInfo: ZnFilterInfo = {
          fieldIndex: oDOMFilter.sFieldIndex,
          filterIndex: oDOMFilter.sFilterIndex,
          filterValue: oDOMFilter.getValue()
        };
        this.onMxFilterer(savedFilterValues, filterInfo);
      };
    });
  }

  /** Custom column filterer that enables the ability to search through multiple comma separated values.
   * Note: This is automatically applied to all columns that have a filter.
   */
  private onMxFilterer(savedFilterValues: ZnSavedFilterValue, filterInfo: ZnFilterInfo) {
    const { filterIndex, filterValue } = filterInfo;
    // Filter out any empty search results. Search will not function correctly if we do not remove queries that are empty,
    // due to how we're comparing property values.
    const propertySearchMapping = {} as ZnSavedFilterValue;
    const filteredValues: string[] = this.getValidFilterValues(filterValue);
    if (filteredValues.length > 0) {
      propertySearchMapping[filterIndex] = filteredValues;
    }
    for (const value in savedFilterValues) {
      propertySearchMapping[value] = this.getValidFilterValues(savedFilterValues[value] as string);
    }
    // Do not update if there were no changes in the search query. This fixes visual issues and false "empty results".
    if (JSON.stringify(propertySearchMapping) === JSON.stringify(this.previousPropertySearchMapping)) {
      return;
    }
    this.previousPropertySearchMapping = propertySearchMapping;
    // Need to do a hard refresh body update first before we do a soft one.
    // True = hard refresh. No parameter = soft refresh.
    // The hard refresh is clearing out any previous state, and removing any unnecessary rows.
    // For example, if you have multiple pages of content already loaded,
    // if the number of items is greater than the number of filtered items, they will remain on the grid.
    this.znRef.widget.bodyUpdate(true);
    const filteredData = getMxFilteredData(this.znRef.data, propertySearchMapping);
    this.updateFilteredData(filteredData);
    this.znRef.widget.bodyUpdateWithScroll();
    // Misalignment's happen if we don't update the size.
    this.znRef.updateSize(false, 0);
    // Edge case. If the current page index is greater than the page count, navigate to the last page.
    // This can happen when the user goes to the next page and then searches for a criteria that has less results.
    if (this.znRef.getPageIndex() > this.znRef.widget.getPageCount()) {
      this.znRef.lastPage();
    }
    // Manually emit the "column:filter" event with the same data ZingGrid emits, in case users need it.
    // We need to do this ourselves since we're overriding their built-in filtering.
    this.znRef.widget.emitEvent('column:filter', { ZGData: filterInfo });
  }

  /** Retrieves values from all zg-filters on the grid.
   * This is required in order to combine filters across different columns. */
  private getZgFilterValues(oDOMFilter: ZSoft.ZGFilter) {
    const savedFilterValues = {} as ZnSavedFilterValue;
    // All properties of the "zg-filter" element are undocumented (including "sFilterIndex").
    this.znRef.widget.aFilters.forEach((filter: ZSoft.ZGFilter) => {
      const hasInput = filter.querySelector('input');
      // Do not save the filter values if it's the same input element that we called this from.
      if (!isNullOrUndefined(hasInput) && hasInput !== oDOMFilter?.oDOMInput) {
        const valueIsEmpty = hasInput.value.trim().length === 0;
        if (!valueIsEmpty) {
          savedFilterValues[filter.sFilterIndex] = hasInput.value;
        }
      }
    });
    return savedFilterValues;
  }

  /** Warning: Do not make any changes unless you have a really good reason to do so.
   * This function relies heavily on undocumented ZingGrid functionality.
   * Information was retrieved by looking at minified code.
   */
  private updateFilteredData(filteredData: ZnDataBulkEdit[]) {
    // The "widget" property and everything belonging to it is undocumented.
    const foundItems: any[] = this.znRef.widget.store.aOrderedData.filter((orderedItem: ZnDataBulkEdit) => {
      const foundInFilteredData = filteredData.find((findItem) => findItem.id === orderedItem.id);
      return !isNullOrUndefined(foundInFilteredData);
    });
    // This is updating the position of the rows internally so that it will show our filtered data in order.
    // Essentially, it's updating which "row" our filteredData should be on.
    foundItems.forEach((item, i) => {
      this.znRef.widget.updateRowMapping(this.znRef.widget.aRowMapping, i, {
        sRecordIndex: item.sRecordIndex
      });
    });
  }

  private insertBulkEdit = () => {
    const znCaption = this.znRef.querySelector('zg-caption');
    if (!isNullOrUndefined(znCaption)) {
      znCaption.innerHTML = `
        <zg-button id='drill-reset-button' slot='tool' class='hidden'>
          <span class='drill-reset-button'>
            <kds-link inverse class='flex' size='s'>Go back to beginning</kds-link>
          </span>
        </zg-button>
        <zg-button id='bulk-edit-button' slot='tool' class='hidden'>
          <kds-icon-edit style="margin-top: -5px"></kds-icon-edit>
        </zg-button>
        `;
      this.znRef.insertBefore(znCaption, this.znRef.firstChild); // noticed that keeping this before adding click event helps

      this.bulkEditButton = znCaption.querySelector('#bulk-edit-button');
      this.bulkEditButton.setAttribute('tooltip', 'Bulk Edit');
      this.bulkEditButton.addEventListener('click', async () => {
        if (!isNullOrUndefined(this.overrideBulkEditButtonHandler)) {
          this.overrideBulkEditButtonHandler();
        } else {
          await this.onBulkEdit();
        }
      });

      this.drillResetButton = znCaption.querySelector('#drill-reset-button');
      this.drillResetButton.setAttribute('tooltip', 'Reset Drill');
      this.drillResetButton.addEventListener('click', () => this.onDrillReset());
    }

  };

  private accordionRenderer(header: string, content: string, cellDOMRef: HTMLElement) {
    if (isNullOrUndefinedOrEmptyString(header) || isNullOrUndefinedOrEmptyString(content)) {
      return;
    }
    const znCellRef = cellDOMRef.querySelector('div'); // a better approach would be if we could find by the pattern [data-field-index=value]
    const dropdownID = getNewUuid();
    znCellRef.innerHTML = `
        <section class='accordion'>
          <input type='checkbox' id='accordion_${dropdownID}'>
          <label for='accordion_${dropdownID}'>
            <span>
              <kds-icon-plus size='xs'></kds-icon-plus>
              <kds-icon-minus size='xs'></kds-icon-minus>
            </span>${header}
          </label>
          <article>
          <p class='expandable-content'>${content}</p>
        </article>
        </section>
      `;

  };

  private readonly dropdownRenderer = (
    dropdownName: 'mx-single-select' | 'mx-multi-select',
    dropdownEvent: 'itemChange' | 'selectionChanged') => (cellData, cellDOMRef: HTMLElement, $cell) => {

    const propertyName = dropdownName === 'mx-single-select' ? 'itemSelected' : 'selectedItems';

    const dropdownRef: HTMLMxSingleSelectElement | HTMLMxMultiSelectElement = document.createElement(dropdownName);
    cellDOMRef.appendChild(dropdownRef);
    Object.keys(cellData || {}).forEach((attr) => dropdownRef[attr] = cellData[attr]);
    dropdownRef.enableDropUp = false;
    ['dropdownOpen', 'dropdownClose'].forEach((eventName) => {
      dropdownRef.addEventListener(eventName, (event: CustomEvent) => {
        const listContainerRef = event.detail;
        if (!isNullOrUndefined(listContainerRef)) {
          $cell.toggleOverflow(listContainerRef, dropdownRef);
        }
      });
    });
    dropdownRef.addEventListener(dropdownEvent, (evt: CustomEvent) => {

      let updatedValue: Object | Object[];
      // Need to get a different value based on if the user is updating single-select or multi-select.
      if (dropdownEvent === 'itemChange') {
        updatedValue = evt.detail.children ? evt.detail.children[0] : evt.detail;
      } else {
        updatedValue = evt.detail;
      }
      cellDOMRef.closest('zing-grid').updateRecord($cell.sTargetRecordIndex, {
        [$cell.sTargetFieldIndex]: {
          ...cellData,
          [propertyName]: updatedValue // this is a hack due to how single-select act
        }
      }, false, true).deselectRows();
    });
  };

  private tagRenderer(status: string, statusText: string, statusIcon: string, cellDOMRef: HTMLElement) {
    const znCellRef = cellDOMRef.querySelector('div');
    znCellRef.innerHTML = `<kds-tag pr-16 kind='${status}' icon='${statusIcon}'>${statusText}</kds-tag>`;
  }

  private toggleBulkEdit(rowsLength: number) {
    if (rowsLength > 0) {
      this.bulkEditButton.classList.remove('hidden');
      this.bulkEditButton.classList.add('flex');
    } else {
      this.bulkEditButton.classList.remove('flex');
      this.bulkEditButton.classList.add('hidden');
    }
  }

  private onDrillReset = () => {
    this.znRef.setData(this._data, false);
    this.populatedData = this.data;
    this.updateContextMenuItems(this.populatedData);
    this.drillResetButton.classList.add('hidden');
  };

  private onBulkEdit = async () => {
    this.clearEditChildren();
    await this.bulkEditModal.createModal();
    this.addEditInputs();
  };

  private readonly onApplyChanges = async () => {
    // After applying changes in bulk edit, we need to update our sorted column UI. It's not happening automatically.
    const { fieldIndex, order } = this.znRef.getSortedColumn();
    await this.bulkEditModal.dismissModal();
    const retrievedValues = Array.from(this.bulkEditModal.querySelectorAll('mx-input-text-box'))
      .reduce((values, element) => {
        if (!isNullOrUndefined(element.value)) {
          values[element.dataset.editProperty] = element.value.toString().trim();
        }
        return values;
      }, {});
    const bulkEditUpdatedData: ZnDataBulkEdit[] = [];
    this.znRef.getSelectedRows().forEach((rowData: ZnDataBulkEdit) => {
      const findRealData: ZnDataBulkEdit = this.znRef.data.find((item: ZnDataBulkEdit) => item.id === rowData.id);
      if (!isNullOrUndefined(findRealData)) {
        Object.entries(retrievedValues).forEach(([key, value]) => {
          findRealData[key] = value;
        });
        bulkEditUpdatedData.push(findRealData);
      }
    });
    this.znRef.setData([...this.znRef.data], false);
    this.znRef.sortColumn(fieldIndex, order);
    this.bulkRecordUpdate.emit(bulkEditUpdatedData);
    this.znRef.deselectRows();
    await this.initMxFilterer();
  };

  private addEditInputs() {
    const itemsAppend = this.znRef.getSelectedRows().length > 1 ? 'items' : 'item';
    this.bulkEditModal.headercontent = `Bulk editing ${this.znRef.getSelectedRows().length} ${itemsAppend}`;
    Object.keys(this._data[0]).sort().forEach((name: string) => {
      // Let's check if this property is being used in the table. We don't want to include properties that are not.
      // Need to cast 'name' as 'any' because ZingGrid is expecting an array here, when their live example takes a string...lol.
      const existsInTable = this.znRef.column(name as any).nStartColumnIndex !== -1;
      if (existsInTable || this._specialAdditions.includes(name)) {
        const inputBox = document.createElement('mx-input-text-box');
        inputBox.classList.add('mb-8');
        inputBox.setAttribute('mask', 'none');
        inputBox.setAttribute('show-value', 'false');
        inputBox.setAttribute('data-edit-property', name);
        inputBox.style.width = '45%';
        inputBox.label = uppercaseFirstLetter(name);
        this.bulkEditModalContainer.appendChild(inputBox);
      }
    });
  }

  private clearEditChildren() {
    while (!isNullOrUndefined(this.bulkEditModalContainer.firstChild)) {
      this.bulkEditModalContainer.firstChild.remove();
    }
  }

  private addContextMenu() {
    if(!this.useMxContextMenu) {
      return;
    }
    const contextMenu = this.znRef.querySelector('zg-menu'); //|| document.createElement('zg-menu');
    if (!isNullOrUndefined(contextMenu)) {
      contextMenu.id = 'mx-context-menu';
      contextMenu.innerHTML = `
      <div class='hidden' id='mx-context-menu-container'>
        <zg-menu-item>
          <zg-icon slot='icon' style='margin-left: -21px'>
            <kds-icon-redo color='interactive'></kds-icon-redo>
            <span slot='label'>Drill Through</span>
          </zg-icon>
        </zg-menu-item>
        <div id='mx-context-menu-items-container' class='flex flex-col'></div>
      </div>
      `;
      this.znRef.setContextMenu(contextMenu.id);
      this.mxContextMenuContainer = this.znRef.querySelector('#mx-context-menu-container');
      this.mxContextMenuItemsContainer = this.znRef.querySelector('#mx-context-menu-items-container');
      this.updateContextMenuItems(this.populatedData);
    }
  }

  private showDrillThroughContextMenu(show: boolean) {
    if (!isNullOrUndefined(this.mxContextMenuContainer)) {
      this.mxContextMenuContainer.classList.add(show ? 'block' : 'hidden');
      this.mxContextMenuContainer.classList.remove(show ? 'hidden' : 'block');
    }
  }

  private updateContextMenuItems(items: Object | Object[]) {
    if(!this.useMxContextMenu) {
      return;
    }
    const filteredItems = Object.keys(items).filter((item) => item !== 'data');
    if (filteredItems.length === 0) {
      this.showDrillThroughContextMenu(false);
      return;
    }

    if (!isNullOrUndefined(this.mxContextMenuItemsContainer)) {
      this.mxContextMenuItemsContainer.innerHTML = '';
      filteredItems.forEach((item) => {
        const zgMenuItem = document.createElement('zg-menu-item');
        zgMenuItem.textContent = uppercaseFirstLetter(item);
        zgMenuItem.addEventListener('click', () => this.updateZnDataSelection(item));
        this.mxContextMenuItemsContainer.appendChild(zgMenuItem);
      });
    }
    this.showDrillThroughContextMenu(true);
  }

  private updateZnDataSelection(item: string) {
    // Ugly solution for now to get rid of an intermittent error when drilling through items.
    setTimeout(() => {
      if (!isNullOrUndefined(this.populatedData[item].data)) {
        this.znRef.setData(this.populatedData[item].data, false);
        this.populatedData = this.populatedData[item];
        this.updateContextMenuItems(this.populatedData);
      } else if (this.populatedData[item].length > 0) {
        this.znRef.setData(this.populatedData[item], false);
        this.updateContextMenuItems([]);
      }
      this.drillResetButton.classList.remove('hidden');
    });
  }

  render() {
    return (
      <Host class='zing-grid-datatable'>
        <mx-modal ref={(ref: HTMLMxModalElement) => this.bulkEditModal = ref}
          headercontent='Bulk Edit'
          size='medium'
          onApplyClick={this.onApplyChanges}>
          <div ref={(ref: HTMLElement) => this.bulkEditModalContainer = ref} class='flex flex-wrap justify-between'>
          </div>
        </mx-modal>
      </Host>
    );
  }
}
