/** Defines the possible sizes for ZingGrid cells. */
import 'mx-zing-grid';

export enum ZNCellHeight {
  Compact = 32,
  Medium = 40,
  Large = 48,
  XLarger = 80,
  XXLarge = 96,
  Auto = 'auto'
}

export interface ZnEnclosedEvent {
  eventName: keyof ZSoft.ZingGridElementEventMap,
  command: (evt: CustomEvent) => any
}

export interface ZnDataBulkEdit {
  id: number | string;
}

export interface ZnFilterInfo {
  fieldIndex: string,
  filterIndex: string,
  filterValue: string
}

export interface ZnSavedFilterValue {
  [key: string]: string | string[];
}

export type ZnData = ZnDataBulkEdit | ZnDataBulkEdit[] | Object | Object[] | { data: Object | Object[] };

export interface ZnRegisterMethods {
  fn: (...args: any[]) => void,
  methodName: string
}
